extensionAttribute.scriptContentsMac:
#!/bin/bash
OUTDATED_PK_HASH="7ec69a1bd679fb7aa7b22ce6b3d0204113b19591db1f1d52014022d8c74f0d53"
get_host_users() { dscl . list /Users | grep -v "^_" | grep '\S' }
function get_license_state() { is_installed=$(which prlsrvctl) if [[ $is_installed ]]; then license_output=$(prlsrvctl info | grep "License:")
if [[ -n "$license_output" ]]; then license_state=$(echo "$license_output" | awk -F "state='" '{print $2}' | awk -F "\'" '{print $1}')
if [[ "$license_state" != "valid" ]]; then echo "<result>$license_state</result>" exit 1 fi else echo "<result>No License found</result>" exit 1 fi else echo "<result>Parallels is not installed</result>" exit 1 fi }
get_pk_hash() { local pvi_path="$1" if [[ ! -f "$pvi_path" ]]; then echo "" return fi grep -o '<UefiPlatformKeySha256>[^<]*</UefiPlatformKeySha256>' "$pvi_path" 2>/dev/null \ | sed 's/<[^>]*>//g' | tr -d '[:space:]' }
get_license_state
is_prlctl_installed=$(which prlctl) if [[ -z "$is_prlctl_installed" ]]; then echo "<result>Parallels is not installed</result>" exit 1 fi
pd_version=$(prlctl --version 2>/dev/null | grep -oE '[0-9]+\.[0-9]+\.[0-9]+' | head -1)
version_gte() { local IFS='.' local -a a b read -r -a a <<< "$1" read -r -a b <<< "$2" local i for i in 0 1 2; do (( ${a[$i]:-0} > ${b[$i]:-0} )) && return 0 (( ${a[$i]:-0} < ${b[$i]:-0} )) && return 1 done return 0 }
if ! version_gte "$pd_version" "26.3.3"; then echo "<result>Parallels Desktop must be updated to 26.3.3 or later (current: $pd_version)</result>" exit 0 fi
COUNT_OUTDATED=0 COUNT_MISSING=0 COUNT_OK=0
for user in $(get_host_users); do [ -n "${user}" ] && [ -d "/Users/${user}" ] || continue
VMS_DATA=$(sudo -u "$user" prlctl list -a -i --json 2>/dev/null \ | awk -F'"' ' /\{[[:space:]]*$/ { depth++; if (depth==1) { id=""; name=""; os=""; home="" }; next } /^[[:space:]]*\},?[[:space:]]*$/ { if (depth==1 && os=="win-11") { gsub(/\\/, "", home); print id "\t" name "\t" home } depth--; next } depth!=1 { next } $2=="ID" { id=$4 } $2=="Name" { name=$4 } $2=="OS" { os=$4 } $2=="Home" { home=$4 } ' || true)
[[ -z "$VMS_DATA" ]] && continue
while IFS=$'\t' read -r vm_id vm_name vm_home || [[ -n "$vm_id" ]]; do [[ -n "$vm_id" ]] || continue pk_hash=$(get_pk_hash "${vm_home}VmInfo.pvi") if [[ -z "$pk_hash" ]]; then COUNT_MISSING=$((COUNT_MISSING + 1)) elif [[ "$pk_hash" == "$OUTDATED_PK_HASH" ]]; then COUNT_OUTDATED=$((COUNT_OUTDATED + 1)) else COUNT_OK=$((COUNT_OK + 1)) fi done <<< "$VMS_DATA"
done
result=""
if [[ "$COUNT_OUTDATED" -gt 0 ]]; then result="One or more VMs have outdated certificates" fi
if [[ "$COUNT_MISSING" -gt 0 ]]; then msg="Waiting for Parallels Tools to be updated on one or more VMs" if [[ -n "$result" ]]; then result="$result; $msg" else result="$msg" fi fi
if [[ "$COUNT_OUTDATED" -eq 0 && "$COUNT_MISSING" -eq 0 && "$COUNT_OK" -gt 0 ]]; then result="All VMs have updated certificates" fi
if [[ -n "$result" ]]; then echo "<result>$result</result>" else echo "<result>No Windows 11 VMs found</result>" fi
